import { BrowserRouter as Router, Routes, Route, Navigate } from "react-router-dom";
import MainLayout from "./layouts/MainLayout";
import DashboardLayout from "./layouts/DashboardLayout";
import Home from "./pages/Home";
import Login from "./pages/Login";
import Register from "./pages/Register";
import EventDetails from "./pages/EventDetails";
import MyBookings from "./pages/MyBookings";
import AdminDashboard from "./pages/Admin/AdminDashboard";
import CreateEvent from "./pages/Admin/CreateEvent";
import ManageEvents from "./pages/Admin/ManageEvents";
import AllBookings from "./pages/Admin/AllBookings";

// Helper functions
const getUser = () => JSON.parse(localStorage.getItem('user') || '{}');
const getToken = () => localStorage.getItem('token');

// Only logged-in users (non-admin)
function UserOnly({ children }) {
  if (!getToken()) return <Navigate to="/login" replace />;
  if (getUser().role === 'admin') return <Navigate to="/admin" replace />;
  return children;
}

// Only admins
function AdminOnly({ children }) {
  if (!getToken()) return <Navigate to="/login" replace />;
  if (getUser().role !== 'admin') return <Navigate to="/home" replace />;
  return children;
}

// Redirect already-logged-in users away from login/register
function GuestOnly({ children }) {
  if (!getToken()) return children;
  if (getUser().role === 'admin') return <Navigate to="/admin" replace />;
  return <Navigate to="/home" replace />;
}

function App() {
  return (
    <Router>
      <Routes>
        {/* Root redirect */}
        <Route path="/" element={
          !getToken() ? <Navigate to="/login" replace /> :
          getUser().role === 'admin' ? <Navigate to="/admin" replace /> :
          <Navigate to="/home" replace />
        } />

        {/* Guest only pages */}
        <Route path="/login" element={<GuestOnly><Login /></GuestOnly>} />
        <Route path="/register" element={<GuestOnly><Register /></GuestOnly>} />

        {/* User pages - no admin allowed */}
        <Route element={<UserOnly><MainLayout /></UserOnly>}>
          <Route path="/home" element={<Home />} />
          <Route path="/events/:id" element={<EventDetails />} />
          <Route path="/my-bookings" element={<MyBookings />} />
        </Route>

        {/* Admin pages - no users allowed */}
        <Route path="/admin" element={<AdminOnly><DashboardLayout /></AdminOnly>}>
          <Route index element={<AdminDashboard />} />
          <Route path="create-event" element={<CreateEvent />} />
          <Route path="manage-events" element={<ManageEvents />} />
          <Route path="bookings" element={<AllBookings />} />
        </Route>

        {/* Catch all */}
        <Route path="*" element={
          !getToken() ? <Navigate to="/login" replace /> :
          getUser().role === 'admin' ? <Navigate to="/admin" replace /> :
          <Navigate to="/home" replace />
        } />
      </Routes>
    </Router>
  );
}
export default App;
